import 'package:device_info_plus/device_info_plus.dart'; import 'package:firebase_auth/firebase_auth.dart'; import 'package:injectable/injectable.dart'; import 'package:package_info_plus/package_info_plus.dart'; import 'package:uuid/uuid.dart'; import '../model/device_model_local.dart'; @injectable class DeviceRegistrationService { Future<DeviceModelLocal> buildThisDevice() async { final info = await DeviceInfoPlugin().androidInfo; final pkg = await PackageInfo.fromPlatform(); final uid = FirebaseAuth.instance.currentUser?.uid ?? ''; return DeviceModelLocal(deviceId: const Uuid().v4(), deviceName: '${info.manufacturer} ${info.model}', type: DeviceTypeLocal.phone, ownerUserId: uid, osVersion: info.version.release, appVersion: pkg.version); } }